     1â†’/**
     2â†’ * MMS Database Migration Runner
     3â†’ *
     4â†’ * Handles database migrations with rollback support for the Metro Fleet
     5â†’ * Mileage Management System. Supports both Drizzle-generated migrations
     6â†’ * and manual SQL migrations.
     7â†’ *
     8â†’ * Features:
     9â†’ * - PostgreSQL advisory locks for concurrent safety
    10â†’ * - Transaction-wrapped execution with automatic rollback
    11â†’ * - Migration history tracking
    12â†’ * - Progress callbacks for UI feedback
    13â†’ * - Manual migration support for extensions/timescaledb/functions
    14â†’ *
    15â†’ * @see specs/003-database-schema.md Section 3.6 (Migrations)
    16â†’ */
    17â†’
    18â†’import { sql } from './connection';
    19â†’import { readdir, readFile } from 'fs/promises';
    20â†’import { join } from 'path';
    21â†’import { logger } from '../logging/logger';
    22â†’
    23â†’/**
    24â†’ * Migration lock ID for PostgreSQL advisory lock
    25â†’ * Using a fixed hash to ensure same lock across processes
    26â†’ */
    27â†’const MIGRATION_LOCK_ID = 2147483647; // Max int32 for uniqueness
    28â†’
    29â†’/**
    30â†’ * Migration record stored in the database
    31â†’ */
    32â†’export interface MigrationRecord {
    33â†’  id: number;
    34â†’  name: string;
    35â†’  hash: string;
    36â†’  executedAt: Date;
    37â†’  executionTimeMs: number;
    38â†’  rollbackSql?: string;
    39â†’}
    40â†’
    41â†’/**
    42â†’ * Migration file content
    43â†’ */
    44â†’export interface Migration {
    45â†’  name: string;
    46â†’  sql: string;
    47â†’  rollbackSql?: string;
    48â†’  isManual: boolean;
    49â†’}
    50â†’
    51â†’/**
    52â†’ * Migration result
    53â†’ */
    54â†’export interface MigrationResult {
    55â†’  name: string;
    56â†’  status: 'applied' | 'skipped' | 'failed' | 'rolled_back';
    57â†’  executionTimeMs: number;
    58â†’  error?: string;
    59â†’}
    60â†’
    61â†’/**
    62â†’ * Migration options
    63â†’ */
    64â†’export interface MigrationOptions {
    65â†’  /** Run only specific migrations by name */
    66â†’  filter?: string[];
    67â†’  /** Dry run - don't actually apply migrations */
    68â†’  dryRun?: boolean;
    69â†’  /** Skip manual migrations (extensions, timescaledb, etc.) */
    70â†’  skipManual?: boolean;
    71â†’  /** Skip Drizzle-generated migrations */
    72â†’  skipDrizzle?: boolean;
    73â†’  /** Include seed data (development only) */
    74â†’  includeSeed?: boolean;
    75â†’  /** Progress callback */
    76â†’  onProgress?: (current: number, total: number, migration: string) => void;
    77â†’}
    78â†’
    79â†’/**
    80â†’ * Overall migration run result
    81â†’ */
    82â†’export interface MigrationRunResult {
    83â†’  success: boolean;
    84â†’  migrations: MigrationResult[];
    85â†’  totalTimeMs: number;
    86â†’  error?: string;
    87â†’}
    88â†’
    89â†’const log = logger.child({ service: 'migrator' });
    90â†’
    91â†’/**
    92â†’ * Compute a simple hash for migration content
    93â†’ */
    94â†’function computeHash(content: string): string {
    95â†’  let hash = 0;
    96â†’  for (let i = 0; i < content.length; i++) {
    97â†’    const char = content.charCodeAt(i);
    98â†’    hash = ((hash << 5) - hash) + char;
    99â†’    hash = hash & hash; // Convert to 32-bit integer
   100â†’  }
   101â†’  return Math.abs(hash).toString(16).padStart(8, '0');
   102â†’}
   103â†’
   104â†’/**
   105â†’ * Database Migrator
   106â†’ *
   107â†’ * Manages database schema migrations with safety features for production use.
   108â†’ */
   109â†’export class Migrator {
   110â†’  private basePath: string;
   111â†’
   112â†’  constructor(basePath?: string) {
   113â†’    // Default to project root drizzle directory
   114â†’    this.basePath = basePath ?? join(process.cwd(), 'drizzle');
   115â†’  }
   116â†’
   117â†’  /**
   118â†’   * Ensure migration history table exists
   119â†’   */
   120â†’  async ensureHistoryTable(): Promise<void> {
   121â†’    await sql`
   122â†’      CREATE TABLE IF NOT EXISTS __mms_migrations (
   123â†’        id SERIAL PRIMARY KEY,
   124â†’        name VARCHAR(255) NOT NULL UNIQUE,
   125â†’        hash VARCHAR(16) NOT NULL,
   126â†’        executed_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
   127â†’        execution_time_ms INTEGER NOT NULL DEFAULT 0,
   128â†’        rollback_sql TEXT
   129â†’      )
   130â†’    `;
   131â†’    log.debug('Migration history table ensured');
   132â†’  }
   133â†’
   134â†’  /**
   135â†’   * Acquire advisory lock for migrations
   136â†’   *
   137â†’   * Returns true if lock was acquired, false if another process holds it.
   138â†’   * Uses pg_try_advisory_lock to avoid blocking.
   139â†’   */
   140â†’  async acquireLock(): Promise<boolean> {
   141â†’    const result = await sql`SELECT pg_try_advisory_lock(${MIGRATION_LOCK_ID}) as acquired`;
   142â†’    const acquired = result[0]?.acquired === true;
   143â†’    if (acquired) {
   144â†’      log.info('Migration lock acquired');
   145â†’    } else {
   146â†’      log.warn('Could not acquire migration lock - another process may be running migrations');
   147â†’    }
   148â†’    return acquired;
   149â†’  }
   150â†’
   151â†’  /**
   152â†’   * Release advisory lock
   153â†’   */
   154â†’  async releaseLock(): Promise<void> {
   155â†’    await sql`SELECT pg_advisory_unlock(${MIGRATION_LOCK_ID})`;
   156â†’    log.info('Migration lock released');
   157â†’  }
   158â†’
   159â†’  /**
   160â†’   * Get list of applied migrations from history table
   161â†’   */
   162â†’  async getAppliedMigrations(): Promise<MigrationRecord[]> {
   163â†’    await this.ensureHistoryTable();
   164â†’    const rows = await sql`
   165â†’      SELECT id, name, hash, executed_at, execution_time_ms, rollback_sql
   166â†’      FROM __mms_migrations
   167â†’      ORDER BY id ASC
   168â†’    `;
   169â†’    return rows.map(row => ({
   170â†’      id: row.id as number,
   171â†’      name: row.name as string,
   172â†’      hash: row.hash as string,
   173â†’      executedAt: row.executed_at as Date,
   174â†’      executionTimeMs: row.execution_time_ms as number,
   175â†’      rollbackSql: row.rollback_sql as string | undefined,
   176â†’    }));
   177â†’  }
   178â†’
   179â†’  /**
   180â†’   * Load manual migrations from drizzle/manual directory
   181â†’   */
   182â†’  async loadManualMigrations(): Promise<Migration[]> {
   183â†’    const manualDir = join(this.basePath, 'manual');
   184â†’    const migrations: Migration[] = [];
   185â†’
   186â†’    try {
   187â†’      const files = await readdir(manualDir);
   188â†’      const sqlFiles = files
   189â†’        .filter(f => f.endsWith('.sql') && !f.startsWith('seed_'))
   190â†’        .sort();
   191â†’
   192â†’      for (const file of sqlFiles) {
   193â†’        const content = await readFile(join(manualDir, file), 'utf-8');
   194â†’        migrations.push({
   195â†’          name: `manual/${file}`,
   196â†’          sql: content,
   197â†’          isManual: true,
   198â†’        });
   199â†’      }
   200â†’    } catch {
   201â†’      // Directory doesn't exist - no manual migrations
   202â†’      log.debug('No manual migrations directory found');
   203â†’    }
   204â†’
   205â†’    return migrations;
   206â†’  }
   207â†’
   208â†’  /**
   209â†’   * Load Drizzle-generated migrations from drizzle/migrations directory
   210â†’   */
   211â†’  async loadDrizzleMigrations(): Promise<Migration[]> {
   212â†’    const drizzleDir = join(this.basePath, 'migrations');
   213â†’    const migrations: Migration[] = [];
   214â†’
   215â†’    try {
   216â†’      const files = await readdir(drizzleDir);
   217â†’      const sqlFiles = files
   218â†’        .filter(f => f.endsWith('.sql'))
   219â†’        .sort();
   220â†’
   221â†’      for (const file of sqlFiles) {
   222â†’        const content = await readFile(join(drizzleDir, file), 'utf-8');
   223â†’        migrations.push({
   224â†’          name: `drizzle/${file}`,
   225â†’          sql: content,
   226â†’          isManual: false,
   227â†’        });
   228â†’      }
   229â†’    } catch {
   230â†’      // Directory doesn't exist - need to run drizzle-kit generate
   231â†’      log.debug('No Drizzle migrations directory found - run "bun run db:generate" first');
   232â†’    }
   233â†’
   234â†’    return migrations;
   235â†’  }
   236â†’
   237â†’  /**
   238â†’   * Load seed data migration (development only)
   239â†’   */
   240â†’  async loadSeedMigration(): Promise<Migration | null> {
   241â†’    const seedFile = join(this.basePath, 'manual', 'seed_development.sql');
   242â†’    try {
   243â†’      const content = await readFile(seedFile, 'utf-8');
   244â†’      return {
   245â†’        name: 'seed/seed_development.sql',
   246â†’        sql: content,
   247â†’        isManual: true,
   248â†’      };
   249â†’    } catch {
   250â†’      return null;
   251â†’    }
   252â†’  }
   253â†’
   254â†’  /**
   255â†’   * Apply a single migration
   256â†’   */
   257â†’  async applyMigration(migration: Migration, dryRun: boolean = false): Promise<MigrationResult> {
   258â†’    const startTime = Date.now();
   259â†’    const hash = computeHash(migration.sql);
   260â†’
   261â†’    if (dryRun) {
   262â†’      log.info({ migration: migration.name }, 'Would apply migration (dry run)');
   263â†’      return {
   264â†’        name: migration.name,
   265â†’        status: 'skipped',
   266â†’        executionTimeMs: 0,
   267â†’      };
   268â†’    }
   269â†’
   270â†’    try {
   271â†’      // Execute migration SQL
   272â†’      // For manual migrations with multiple statements, we need unsafe mode
   273â†’      await sql.unsafe(migration.sql);
   274â†’
   275â†’      const executionTimeMs = Date.now() - startTime;
   276â†’
   277â†’      // Record in history
   278â†’      await sql`
   279â†’        INSERT INTO __mms_migrations (name, hash, execution_time_ms, rollback_sql)
   280â†’        VALUES (${migration.name}, ${hash}, ${executionTimeMs}, ${migration.rollbackSql ?? null})
   281â†’        ON CONFLICT (name) DO UPDATE SET
   282â†’          hash = ${hash},
   283â†’          executed_at = CURRENT_TIMESTAMP,
   284â†’          execution_time_ms = ${executionTimeMs}
   285â†’      `;
   286â†’
   287â†’      log.info({ migration: migration.name, executionTimeMs }, 'Migration applied');
   288â†’
   289â†’      return {
   290â†’        name: migration.name,
   291â†’        status: 'applied',
   292â†’        executionTimeMs,
   293â†’      };
   294â†’    } catch (error) {
   295â†’      const executionTimeMs = Date.now() - startTime;
   296â†’      const errorMessage = error instanceof Error ? error.message : String(error);
   297â†’
   298â†’      log.error({ migration: migration.name, error: errorMessage }, 'Migration failed');
   299â†’
   300â†’      return {
   301â†’        name: migration.name,
   302â†’        status: 'failed',
   303â†’        executionTimeMs,
   304â†’        error: errorMessage,
   305â†’      };
   306â†’    }
   307â†’  }
   308â†’
   309â†’  /**
   310â†’   * Rollback a migration using its stored rollback SQL
   311â†’   */
   312â†’  async rollbackMigration(record: MigrationRecord): Promise<MigrationResult> {
   313â†’    if (!record.rollbackSql) {
   314â†’      log.warn({ migration: record.name }, 'No rollback SQL available for migration');
   315â†’      return {
   316â†’        name: record.name,
   317â†’        status: 'skipped',
   318â†’        executionTimeMs: 0,
   319â†’        error: 'No rollback SQL available',
   320â†’      };
   321â†’    }
   322â†’
   323â†’    const startTime = Date.now();
   324â†’
   325â†’    try {
   326â†’      await sql.unsafe(record.rollbackSql);
   327â†’
   328â†’      // Remove from history
   329â†’      await sql`DELETE FROM __mms_migrations WHERE name = ${record.name}`;
   330â†’
   331â†’      const executionTimeMs = Date.now() - startTime;
   332â†’      log.info({ migration: record.name, executionTimeMs }, 'Migration rolled back');
   333â†’
   334â†’      return {
   335â†’        name: record.name,
   336â†’        status: 'rolled_back',
   337â†’        executionTimeMs,
   338â†’      };
   339â†’    } catch (error) {
   340â†’      const executionTimeMs = Date.now() - startTime;
   341â†’      const errorMessage = error instanceof Error ? error.message : String(error);
   342â†’
   343â†’      log.error({ migration: record.name, error: errorMessage }, 'Rollback failed');
   344â†’
   345â†’      return {
   346â†’        name: record.name,
   347â†’        status: 'failed',
   348â†’        executionTimeMs,
   349â†’        error: errorMessage,
   350â†’      };
   351â†’    }
   352â†’  }
   353â†’
   354â†’  /**
   355â†’   * Run all pending migrations
   356â†’   *
   357â†’   * Executes manual migrations first (extensions, timescaledb, functions),
   358â†’   * then Drizzle-generated migrations in order.
   359â†’   */
   360â†’  async migrate(options: MigrationOptions = {}): Promise<MigrationRunResult> {
   361â†’    const startTime = Date.now();
   362â†’    const results: MigrationResult[] = [];
   363â†’
   364â†’    log.info({ options }, 'Starting migration run');
   365â†’
   366â†’    // Acquire lock
   367â†’    const lockAcquired = await this.acquireLock();
   368â†’    if (!lockAcquired) {
   369â†’      return {
   370â†’        success: false,
   371â†’        migrations: [],
   372â†’        totalTimeMs: Date.now() - startTime,
   373â†’        error: 'Could not acquire migration lock - another process may be running migrations',
   374â†’      };
   375â†’    }
   376â†’
   377â†’    try {
   378â†’      // Get applied migrations
   379â†’      const applied = await this.getAppliedMigrations();
   380â†’      const appliedNames = new Set(applied.map(m => m.name));
   381â†’
   382â†’      // Load all migrations
   383â†’      const migrations: Migration[] = [];
   384â†’
   385â†’      if (!options.skipManual) {
   386â†’        const manual = await this.loadManualMigrations();
   387â†’        migrations.push(...manual);
   388â†’      }
   389â†’
   390â†’      if (!options.skipDrizzle) {
   391â†’        const drizzle = await this.loadDrizzleMigrations();
   392â†’        migrations.push(...drizzle);
   393â†’      }
   394â†’
   395â†’      // Filter if specified
   396â†’      let pending = migrations.filter(m => !appliedNames.has(m.name));
   397â†’      if (options.filter?.length) {
   398â†’        pending = pending.filter(m => options.filter!.some(f => m.name.includes(f)));
   399â†’      }
   400â†’
   401â†’      log.info({ total: migrations.length, pending: pending.length }, 'Migrations loaded');
   402â†’
   403â†’      // Apply pending migrations
   404â†’      for (let i = 0; i < pending.length; i++) {
   405â†’        const migration = pending[i];
   406â†’        options.onProgress?.(i + 1, pending.length, migration.name);
   407â†’
   408â†’        const result = await this.applyMigration(migration, options.dryRun);
   409â†’        results.push(result);
   410â†’
   411â†’        // Stop on failure
   412â†’        if (result.status === 'failed') {
   413â†’          log.error({ migration: migration.name }, 'Migration failed - stopping');
   414â†’          break;
   415â†’        }
   416â†’      }
   417â†’
   418â†’      // Apply seed data if requested and in development
   419â†’      if (options.includeSeed && process.env['NODE_ENV'] === 'development') {
   420â†’        const seed = await this.loadSeedMigration();
   421â†’        if (seed && !appliedNames.has(seed.name)) {
   422â†’          options.onProgress?.(pending.length + 1, pending.length + 1, seed.name);
   423â†’          const result = await this.applyMigration(seed, options.dryRun);
   424â†’          results.push(result);
   425â†’        }
   426â†’      }
