/**
 * MMS Redis Connection
 *
 * Provides Redis connection utilities for:
 * - BullMQ job queues
 * - Session storage
 * - Caching layer
 *
 * @see specs/003-database-schema.md Section 3.2
 */

import Redis, { type RedisOptions } from 'ioredis';

export interface RedisConfig {
  host: string;
  port: number;
  password?: string;
  db?: number;
  maxRetriesPerRequest: number | null;
  enableReadyCheck: boolean;
  lazyConnect?: boolean;
  keyPrefix?: string;
}

const defaultConfig: RedisConfig = {
  host: process.env['REDIS_HOST'] ?? 'localhost',
  port: parseInt(process.env['REDIS_PORT'] ?? '6379', 10),
  password: process.env['REDIS_PASSWORD'],
  db: parseInt(process.env['REDIS_DB'] ?? '0', 10),
  maxRetriesPerRequest: null, // Required for BullMQ
  enableReadyCheck: true,
  lazyConnect: false,
};

let redisClient: Redis | null = null;
let bullmqConnection: Redis | null = null;

/**
 * Get or create the main Redis client
 * Used for caching and general operations
 */
export function getRedisClient(config: Partial<RedisConfig> = {}): Redis {
  if (!redisClient) {
    const mergedConfig: RedisOptions = {
      ...defaultConfig,
      ...config,
      keyPrefix: config.keyPrefix ?? 'mms:',
    };
    redisClient = new Redis(mergedConfig);

    redisClient.on('error', (err) => {
      console.error('[Redis] Connection error:', err.message);
    });

    redisClient.on('connect', () => {
      console.info('[Redis] Connected successfully');
    });

    redisClient.on('ready', () => {
      console.info('[Redis] Ready to accept commands');
    });
  }

  return redisClient;
}

/**
 * Get or create a Redis connection for BullMQ
 * Separate instance to avoid blocking queue operations
 */
export function getBullMQConnection(config: Partial<RedisConfig> = {}): Redis {
  if (!bullmqConnection) {
    const mergedConfig: RedisOptions = {
      ...defaultConfig,
      ...config,
      maxRetriesPerRequest: null, // Critical for BullMQ
      enableReadyCheck: false, // Faster startup for workers
    };
    bullmqConnection = new Redis(mergedConfig);

    bullmqConnection.on('error', (err) => {
      console.error('[BullMQ Redis] Connection error:', err.message);
    });
  }

  return bullmqConnection;
}

/**
 * Check Redis health
 */
export async function checkRedisHealth(): Promise<boolean> {
  try {
    const client = getRedisClient();
    const result = await client.ping();
    return result === 'PONG';
  } catch {
    return false;
  }
}

/**
 * Close all Redis connections
 * Call during graceful shutdown
 */
export async function closeRedisConnections(): Promise<void> {
  const closePromises: Promise<void>[] = [];

  if (redisClient) {
    closePromises.push(
      redisClient.quit().then(() => {
        redisClient = null;
      })
    );
  }

  if (bullmqConnection) {
    closePromises.push(
      bullmqConnection.quit().then(() => {
        bullmqConnection = null;
      })
    );
  }

  await Promise.all(closePromises);
  console.info('[Redis] All connections closed');
}

/**
 * Cache utilities
 */
export const cache = {
  /**
   * Get cached value
   */
  async get<T>(key: string): Promise<T | null> {
    const client = getRedisClient();
    const value = await client.get(key);
    if (!value) return null;
    try {
      return JSON.parse(value) as T;
    } catch {
      return value as unknown as T;
    }
  },

  /**
   * Set cached value with optional TTL
   */
  async set<T>(key: string, value: T, ttlSeconds?: number): Promise<void> {
    const client = getRedisClient();
    const serialized = typeof value === 'string' ? value : JSON.stringify(value);
    if (ttlSeconds) {
      await client.setex(key, ttlSeconds, serialized);
    } else {
      await client.set(key, serialized);
    }
  },

  /**
   * Delete cached value
   */
  async del(key: string): Promise<void> {
    const client = getRedisClient();
    await client.del(key);
  },

  /**
   * Delete multiple keys by pattern
   */
  async delByPattern(pattern: string): Promise<number> {
    const client = getRedisClient();
    const keys = await client.keys(pattern);
    if (keys.length === 0) return 0;
    return client.del(...keys);
  },
};

/**
 * MMS Logging Configuration
 *
 * Structured logging with Pino for consistent log format across all services.
 * Features:
 * - JSON format in production
 * - Pretty print in development
 * - Sensitive field redaction
 * - Request ID propagation
 * - OpenTelemetry trace context
 *
 * @see specs/004-backend-specification.md Section 4.14
 */

import pino, { type Logger, type LoggerOptions } from 'pino';

const isDevelopment = process.env['NODE_ENV'] === 'development';

/**
 * Fields to redact from logs (prevents PII/secrets leakage)
 */
const REDACT_PATHS = [
  'password',
  'passwordHash',
  'password_hash',
  'token',
  'accessToken',
  'refreshToken',
  'apiKey',
  'api_key',
  'authorization',
  'cookie',
  'creditCard',
  'ssn',
  '*.password',
  '*.token',
  '*.apiKey',
  'req.headers.authorization',
  'req.headers.cookie',
];

/**
 * Base logger configuration
 */
const baseOptions: LoggerOptions = {
  level: process.env['LOG_LEVEL'] ?? (isDevelopment ? 'debug' : 'info'),
  redact: {
    paths: REDACT_PATHS,
    censor: '[REDACTED]',
  },
  formatters: {
    level: (label) => ({ level: label }),
    bindings: (bindings) => ({
      pid: bindings.pid,
      host: bindings.hostname,
      service: process.env['SERVICE_NAME'] ?? 'mms',
    }),
  },
  timestamp: pino.stdTimeFunctions.isoTime,
  base: {
    env: process.env['NODE_ENV'] ?? 'development',
  },
};

/**
 * Development transport (pretty print)
 */
const developmentTransport = {
  target: 'pino-pretty',
  options: {
    colorize: true,
    translateTime: 'HH:MM:ss.l',
    ignore: 'pid,hostname',
    singleLine: false,
  },
};

/**
 * Create the root logger instance
 */
function createLogger(): Logger {
  if (isDevelopment) {
    return pino({
      ...baseOptions,
      transport: developmentTransport,
    });
  }

  return pino(baseOptions);
}

/**
 * Root logger instance
 */
export const logger = createLogger();

/**
 * Create a child logger with additional context
 * Use for service-specific or request-specific logging
 */
export function createChildLogger(context: Record<string, unknown>): Logger {
  return logger.child(context);
}

/**
 * Create a request-scoped logger with trace context
 */
export function createRequestLogger(requestId: string, traceId?: string): Logger {
  return logger.child({
    requestId,
    ...(traceId && { traceId }),
  });
}

/**
 * Log level type
 */
export type LogLevel = 'trace' | 'debug' | 'info' | 'warn' | 'error' | 'fatal';

/**
 * Structured error logging helper
 */
export function logError(
  log: Logger,
  error: Error,
  context?: Record<string, unknown>
): void {
  const errObj: Record<string, unknown> = {
    message: error.message,
    name: error.name,
    stack: error.stack,
  };
  if (error.cause) {
    errObj.cause = error.cause;
  }
  log.error(
    {
      err: errObj,
      ...context,
    },
    error.message
  );
}

/**
 * Performance timing helper
 */
export function logTiming(
  log: Logger,
  operation: string,
  durationMs: number,
  context?: Record<string, unknown>
): void {
  const level: LogLevel = durationMs > 1000 ? 'warn' : 'info';
  log[level](
    {
      operation,
      durationMs,
      ...context,
    },
    `${operation} completed in ${durationMs}ms`
  );
}

export default logger;

