/**
 * MMS OpenTelemetry Tracing Configuration
 *
 * Provides distributed tracing for all MMS services.
 * Integrates with Pino logging for correlated trace context.
 *
 * Features:
 * - Automatic span context propagation
 * - Span attribute helpers for domain-specific data
 * - Integration with existing Pino logger
 * - Configurable exporters (OTLP, Jaeger, Console)
 *
 * @see specs/004-domain-services.md - All services emit OpenTelemetry traces
 */

import {
  trace,
  context,
  SpanStatusCode,
  SpanKind,
  type Span,
  type Tracer,
  type Context,
  type SpanOptions,
  type Attributes,
} from '@opentelemetry/api';
import {
  SEMRESATTRS_SERVICE_NAME,
  SEMRESATTRS_SERVICE_VERSION,
  SEMRESATTRS_DEPLOYMENT_ENVIRONMENT,
} from '@opentelemetry/semantic-conventions';

const SERVICE_NAME = process.env['SERVICE_NAME'] ?? 'mms';
const SERVICE_VERSION = process.env['SERVICE_VERSION'] ?? '0.1.0';
const ENVIRONMENT = process.env['NODE_ENV'] ?? 'development';

/**
 * Domain-specific span attributes for MMS
 */
export const MmsAttributes = {
  // Train attributes
  TRAIN_ID: 'mms.train.id',
  TRAIN_NUMBER: 'mms.train.number',
  FLEET_ID: 'mms.fleet.id',

  // PM attributes
  PM_SCHEDULE_ID: 'mms.pm.schedule_id',
  PM_TYPE_CODE: 'mms.pm.type_code',
  PM_STATUS: 'mms.pm.status',

  // Depot attributes
  DEPOT_ID: 'mms.depot.id',
  DEPOT_CODE: 'mms.depot.code',

  // Mileage attributes
  MILEAGE_KM: 'mms.mileage.km',
  DAILY_KM: 'mms.mileage.daily_km',

  // Ingestion attributes
  INGESTION_FILE: 'mms.ingestion.file',
  INGESTION_JOB_ID: 'mms.ingestion.job_id',
  INGESTION_RECORD_COUNT: 'mms.ingestion.record_count',
  INGESTION_RECORDS: 'mms.ingestion.records',
  INGESTION_VALID: 'mms.ingestion.valid',
  INGESTION_INVALID: 'mms.ingestion.invalid',

  // Optimizer attributes
  OPTIMIZER_JOB_ID: 'mms.optimizer.job_id',
  OPTIMIZER_SOLVER: 'mms.optimizer.solver',
  OPTIMIZER_SOLVE_TIME_MS: 'mms.optimizer.solve_time_ms',
  OPTIMIZER_OBJECTIVE: 'mms.optimizer.objective',
  OPTIMIZER_STATUS: 'mms.optimizer.status',

  // Baseline attributes
  BASELINE_ID: 'mms.baseline.id',
  BASELINE_VERSION: 'mms.baseline.version',

  // Scenario attributes
  SCENARIO_ID: 'mms.scenario.id',
  SCENARIO_NAME: 'mms.scenario.name',

  // Queue attributes
  QUEUE_NAME: 'mms.queue.name',
  JOB_ID: 'mms.job.id',
  JOB_ATTEMPT: 'mms.job.attempt',

  // User attributes
  USER_ID: 'mms.user.id',
  USER_EMAIL: 'mms.user.email',

  // Database attributes
  DB_OPERATION: 'mms.db.operation',
  DB_TABLE: 'mms.db.table',
  DB_ROWS_AFFECTED: 'mms.db.rows_affected',

  // Error attributes
  ERROR_CODE: 'mms.error.code',
  ERROR_TYPE: 'mms.error.type',
} as const;

/**
 * Get the configured tracer for a service
 */
export function getTracer(serviceName?: string): Tracer {
  return trace.getTracer(serviceName ?? SERVICE_NAME, SERVICE_VERSION);
}

/**
 * Get service-level attributes for span context
 */
export function getServiceAttributes(): Attributes {
  return {
    [SEMRESATTRS_SERVICE_NAME]: SERVICE_NAME,
    [SEMRESATTRS_SERVICE_VERSION]: SERVICE_VERSION,
    [SEMRESATTRS_DEPLOYMENT_ENVIRONMENT]: ENVIRONMENT,
  };
}

/**
 * Start a new span for an operation
 */
export function startSpan(
  name: string,
  options?: SpanOptions & { tracer?: Tracer }
): Span {
  const tracer = options?.tracer ?? getTracer();
  return tracer.startSpan(name, {
    ...options,
    attributes: {
      ...getServiceAttributes(),
      ...options?.attributes,
    },
  });
}

/**
 * Execute a function within a traced span
 *
 * Automatically records errors and sets span status.
 *
 * @example
 * const result = await withSpan('processRecord', async (span) => {
 *   span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
 *   return processRecord(record);
 * });
 */
export async function withSpan<T>(
  name: string,
  fn: (span: Span) => Promise<T>,
  options?: SpanOptions & { tracer?: Tracer }
): Promise<T> {
  const tracer = options?.tracer ?? getTracer();
  const span = tracer.startSpan(name, {
    kind: SpanKind.INTERNAL,
    ...options,
    attributes: {
      ...getServiceAttributes(),
      ...options?.attributes,
    },
  });

  const ctx = trace.setSpan(context.active(), span);

  try {
    const result = await context.with(ctx, () => fn(span));
    span.setStatus({ code: SpanStatusCode.OK });
    return result;
  } catch (error) {
    recordSpanError(span, error);
    throw error;
  } finally {
    span.end();
  }
}

/**
 * Synchronous version of withSpan
 */
export function withSpanSync<T>(
  name: string,
  fn: (span: Span) => T,
  options?: SpanOptions & { tracer?: Tracer }
): T {
  const tracer = options?.tracer ?? getTracer();
  const span = tracer.startSpan(name, {
    kind: SpanKind.INTERNAL,
    ...options,
    attributes: {
      ...getServiceAttributes(),
      ...options?.attributes,
    },
  });

  const ctx = trace.setSpan(context.active(), span);

  try {
    const result = context.with(ctx, () => fn(span));
    span.setStatus({ code: SpanStatusCode.OK });
    return result;
  } catch (error) {
    recordSpanError(span, error);
    throw error;
  } finally {
    span.end();
  }
}

/**
 * Record an error on a span
 */
export function recordSpanError(span: Span, error: unknown): void {
  span.setStatus({
    code: SpanStatusCode.ERROR,
    message: error instanceof Error ? error.message : String(error),
  });

  if (error instanceof Error) {
    span.recordException(error);

    // Add MMS error attributes if available
    const mmsError = error as Error & { code?: string; statusCode?: number };
    if (mmsError.code) {
      span.setAttribute(MmsAttributes.ERROR_CODE, mmsError.code);
    }
    if (mmsError.statusCode) {
      span.setAttribute('http.status_code', mmsError.statusCode);
    }
    span.setAttribute(MmsAttributes.ERROR_TYPE, error.name);
  }
}

/**
 * Add an event to the current span
 */
export function addSpanEvent(
  name: string,
  attributes?: Attributes,
  span?: Span
): void {
  const currentSpan = span ?? trace.getActiveSpan();
  currentSpan?.addEvent(name, attributes);
}

/**
 * Get the current active span
 */
export function getActiveSpan(): Span | undefined {
  return trace.getActiveSpan();
}

/**
 * Get the current trace ID (for correlation with logs)
 */
export function getTraceId(): string | undefined {
  return getActiveSpan()?.spanContext().traceId;
}

/**
 * Get the current span ID
 */
export function getSpanId(): string | undefined {
  return getActiveSpan()?.spanContext().spanId;
}

/**
 * Create a trace context object for logging
 */
export function getTraceContext(): { traceId?: string; spanId?: string } {
  const span = getActiveSpan();
  if (!span) return {};

  const ctx = span.spanContext();
  return {
    traceId: ctx.traceId,
    spanId: ctx.spanId,
  };
}

/**
 * Execute a function within the context of an existing span
 */
export async function withContext<T>(
  ctx: Context,
  fn: () => Promise<T>
): Promise<T> {
  return context.with(ctx, fn);
}

/**
 * Create a linked span (for async operations that continue from another trace)
 */
export function createLinkedSpan(
  name: string,
  parentSpan: Span,
  options?: SpanOptions
): Span {
  const tracer = getTracer();
  return tracer.startSpan(name, {
    ...options,
    links: [
      ...(options?.links ?? []),
      { context: parentSpan.spanContext() },
    ],
    attributes: {
      ...getServiceAttributes(),
      ...options?.attributes,
    },
  });
}

/**
 * Span kind constants for convenience
 */
export { SpanKind, SpanStatusCode } from '@opentelemetry/api';

/**
 * Type exports
 */
export type { Span, Tracer, Context, SpanOptions, Attributes };

