/**
 * MMS Date/Time Utilities
 *
 * Timezone-aware date utilities for PM scheduling and compliance windows.
 * All operations use Asia/Hong_Kong timezone as the default depot timezone.
 *
 * @see specs/004-backend-specification.md Section 4.4
 */

import {
  addDays,
  addMonths,
  addWeeks,
  differenceInDays,
  endOfDay,
  endOfWeek,
  format,
  isAfter,
  isBefore,
  isValid,
  isWithinInterval,
  parseISO,
  startOfDay,
  startOfWeek,
} from 'date-fns';
import { formatInTimeZone, toZonedTime, fromZonedTime } from 'date-fns-tz';

/** Default timezone for MMS operations */
export const DEFAULT_TIMEZONE = 'Asia/Hong_Kong';

/** PM compliance window tolerance (Â±10%) */
export const COMPLIANCE_TOLERANCE_PCT = 0.10;

/** Day type for service demand */
export type DayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';

// =============================================================================
// Timezone Utilities
// =============================================================================

/**
 * Convert UTC date to local timezone
 */
export function toLocalTime(date: Date, timezone: string = DEFAULT_TIMEZONE): Date {
  return toZonedTime(date, timezone);
}

/**
 * Convert local timezone to UTC
 */
export function toUtc(date: Date, timezone: string = DEFAULT_TIMEZONE): Date {
  return fromZonedTime(date, timezone);
}

/**
 * Format date in specific timezone
 */
export function formatInTimezone(
  date: Date,
  formatStr: string,
  timezone: string = DEFAULT_TIMEZONE
): string {
  return formatInTimeZone(date, timezone, formatStr);
}

/**
 * Get current date in timezone (start of day)
 */
export function getTodayInTimezone(timezone: string = DEFAULT_TIMEZONE): Date {
  const now = new Date();
  const zoned = toZonedTime(now, timezone);
  return startOfDay(zoned);
}

// =============================================================================
// Compliance Window Utilities
// =============================================================================

export interface ComplianceWindow {
  start: Date;
  end: Date;
  targetDate: Date;
  isValid: boolean;
}

/**
 * Calculate compliance window for a PM
 *
 * The compliance window is calculated based on the PM interval (km or months)
 * with a Â±10% tolerance.
 *
 * @param lastPmDate - Date of last PM completion
 * @param intervalMonths - PM interval in months (e.g., 12 for annual)
 * @param intervalKm - PM interval in km (e.g., 180000)
 * @param currentMileageKm - Current train mileage
 * @param dailyKmRate - Expected daily mileage accrual
 */
export function calculateComplianceWindow(options: {
  lastPmDate: Date;
  intervalMonths?: number;
  intervalKm?: number;
  currentMileageKm?: number;
  dailyKmRate?: number;
  lastPmMileageKm?: number;
}): ComplianceWindow {
  const {
    lastPmDate,
    intervalMonths,
    intervalKm,
    currentMileageKm,
    dailyKmRate = 280, // Default: 280 km/day
    lastPmMileageKm = 0,
  } = options;

  let targetDate: Date;
  let windowStart: Date;
  let windowEnd: Date;

  // Time-based trigger
  if (intervalMonths) {
    targetDate = addMonths(lastPmDate, intervalMonths);
    const toleranceDays = Math.floor(intervalMonths * 30 * COMPLIANCE_TOLERANCE_PCT);
    windowStart = addDays(targetDate, -toleranceDays);
    windowEnd = addDays(targetDate, toleranceDays);
  }
  // Mileage-based trigger
  else if (intervalKm && currentMileageKm !== undefined) {
    const targetMileage = lastPmMileageKm + intervalKm;
    const remainingKm = targetMileage - currentMileageKm;
    const daysToTarget = Math.ceil(remainingKm / dailyKmRate);

    targetDate = addDays(new Date(), daysToTarget);

    const toleranceKm = intervalKm * COMPLIANCE_TOLERANCE_PCT;
    const toleranceDays = Math.ceil(toleranceKm / dailyKmRate);

    windowStart = addDays(targetDate, -toleranceDays);
    windowEnd = addDays(targetDate, toleranceDays);
  } else {
    // Fallback: use last PM date + 1 year
    targetDate = addMonths(lastPmDate, 12);
    windowStart = addMonths(targetDate, -1);
    windowEnd = addMonths(targetDate, 1);
  }

  return {
    start: windowStart,
    end: windowEnd,
    targetDate,
    isValid: true,
  };
}

/**
 * Check if a date falls within a compliance window
 */
export function isWithinComplianceWindow(date: Date, window: ComplianceWindow): boolean {
  return isWithinInterval(date, { start: window.start, end: window.end });
}

/**
 * Check if a PM is overdue (past compliance window)
 */
export function isPmOverdue(window: ComplianceWindow, currentDate: Date = new Date()): boolean {
  return isAfter(currentDate, window.end);
}

/**
 * Check if a PM is upcoming (within compliance window or before)
 */
export function isPmUpcoming(window: ComplianceWindow, currentDate: Date = new Date()): boolean {
  return isBefore(currentDate, window.start);
}

/**
 * Get days until PM compliance window ends
 */
export function getDaysToDeadline(window: ComplianceWindow, currentDate: Date = new Date()): number {
  return differenceInDays(window.end, currentDate);
}

// =============================================================================
// PM Hierarchy Utilities
// =============================================================================

/** PM code hierarchy (higher PMs satisfy lower PMs) */
export const PM_HIERARCHY: Record<string, string[]> = {
  'OVERHAUL': ['C4', 'C3', 'C2', 'C1'],
  'C4': ['C3', 'C2', 'C1'],
  'C3': ['C2', 'C1'],
  'C2': ['C1'],
  'C1': [],
};

/**
 * Get list of PM codes that a given PM satisfies
 */
export function getSatisfiedPmCodes(pmCode: string): string[] {
  return PM_HIERARCHY[pmCode] ?? [];
}

/**
 * Check if completing PM A satisfies PM B
 */
export function pmSatisfies(pmCodeA: string, pmCodeB: string): boolean {
  const satisfies = PM_HIERARCHY[pmCodeA];
  return satisfies?.includes(pmCodeB) ?? false;
}

// =============================================================================
// Mileage Projection Utilities
// =============================================================================

export interface MileageProjection {
  date: Date;
  projectedMileageKm: number;
  dailyRateKm: number;
  confidence: 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';
}

/**
 * Project mileage at a future date
 *
 * @param currentMileageKm - Current train mileage
 * @param targetDate - Date to project to
 * @param dailyRateKm - Daily mileage accrual rate
 * @param currentDate - Starting date (defaults to today)
 */
export function projectMileage(
  currentMileageKm: number,
  targetDate: Date,
  dailyRateKm: number = 280,
  currentDate: Date = new Date()
): MileageProjection {
  const daysDiff = differenceInDays(targetDate, currentDate);
  const projectedKm = currentMileageKm + daysDiff * dailyRateKm;

  // Confidence decreases with projection distance
  let confidence: MileageProjection['confidence'];
  if (daysDiff <= 30) {
    confidence = 'HIGH';
  } else if (daysDiff <= 90) {
    confidence = 'MEDIUM';
  } else if (daysDiff <= 365) {
    confidence = 'LOW';
  } else {
    confidence = 'ESTIMATED';
  }

  return {
    date: targetDate,
    projectedMileageKm: Math.round(projectedKm),
    dailyRateKm,
    confidence,
  };
}

/**
 * Calculate date when train will reach target mileage
 */
export function projectDateForMileage(
  currentMileageKm: number,
  targetMileageKm: number,
  dailyRateKm: number = 280,
  currentDate: Date = new Date()
): Date {
  const remainingKm = targetMileageKm - currentMileageKm;
  const daysToTarget = Math.ceil(remainingKm / dailyRateKm);
  return addDays(currentDate, daysToTarget);
}

// =============================================================================
// Week/Period Utilities
// =============================================================================

/**
 * Get week boundaries (Monday-Sunday)
 */
export function getWeekBoundaries(date: Date): { start: Date; end: Date } {
  return {
    start: startOfWeek(date, { weekStartsOn: 1 }), // Monday
    end: endOfWeek(date, { weekStartsOn: 1 }), // Sunday
  };
}

/**
 * Get day type for a given date
 */
export function getDayType(date: Date): DayType {
  const dayOfWeek = date.getDay();
  if (dayOfWeek === 0) return 'SUNDAY';
  if (dayOfWeek === 6) return 'SATURDAY';
  return 'WEEKDAY';
  // Note: Holiday detection requires external calendar data
}

/**
 * Generate date range array
 */
export function generateDateRange(start: Date, end: Date): Date[] {
  const dates: Date[] = [];
  let current = startOfDay(start);
  const endDay = endOfDay(end);

  while (isBefore(current, endDay) || current.getTime() === startOfDay(endDay).getTime()) {
    dates.push(current);
    current = addDays(current, 1);
  }

  return dates;
}

/**
 * Generate weekly periods for a date range
 */
export function generateWeeklyPeriods(
  start: Date,
  end: Date
): Array<{ start: Date; end: Date }> {
  const periods: Array<{ start: Date; end: Date }> = [];
  let current = startOfWeek(start, { weekStartsOn: 1 });

  while (isBefore(current, end)) {
    periods.push({
      start: current,
      end: endOfWeek(current, { weekStartsOn: 1 }),
    });
    current = addWeeks(current, 1);
  }

  return periods;
}

// =============================================================================
// Parsing Utilities
// =============================================================================

/**
 * Parse date string (YYYY-MM-DD format)
 */
export function parseDateString(dateStr: string): Date | null {
  const parsed = parseISO(dateStr);
  return isValid(parsed) ? parsed : null;
}

/**
 * Format date for display
 */
export function formatDisplayDate(date: Date, formatStr: string = 'yyyy-MM-dd'): string {
  return format(date, formatStr);
}

/**
 * Format date for API response
 */
export function formatIsoDate(date: Date): string {
  return date.toISOString();
}

// =============================================================================
// Performance Utilities
// =============================================================================

/**
 * Measure duration of an async operation
 */
export async function measureDuration<T>(
  operation: () => Promise<T>
): Promise<{ result: T; durationMs: number }> {
  const start = performance.now();
  const result = await operation();
  const durationMs = Math.round(performance.now() - start);
  return { result, durationMs };
}

/**
 * Create a stopwatch for manual timing
 */
export function createStopwatch(): {
  start: () => void;
  stop: () => number;
  elapsed: () => number;
} {
  let startTime: number | null = null;
  let endTime: number | null = null;

  return {
    start: () => {
      startTime = performance.now();
      endTime = null;
    },
    stop: () => {
      if (startTime === null) return 0;
      endTime = performance.now();
      return Math.round(endTime - startTime);
    },
    elapsed: () => {
      if (startTime === null) return 0;
      const end = endTime ?? performance.now();
      return Math.round(end - startTime);
    },
  };
}

