     2â†’ * MMS Resilience Utilities
     3â†’ *
     4â†’ * Provides retry and circuit breaker patterns for handling transient failures.
     5â†’ * Critical for integration with external systems (Maximo, OCC) and for
     6â†’ * maintaining service availability during infrastructure issues.
     7â†’ *
     8â†’ * @see specs/007-integration.md - External system integration patterns
     9â†’ * @see specs/004-domain-services.md - Service reliability requirements
    10â†’ */
    11â†’
    12â†’import { withSpan, addSpanEvent, SpanKind } from '../tracing';
    13â†’import { TimeoutError, ExternalServiceError, ServiceUnavailableError } from '../errors';
    14â†’import { logger } from '../logging/logger';
    15â†’
    16â†’// =============================================================================
    17â†’// Retry Configuration & Implementation
    18â†’// =============================================================================
    19â†’
    20â†’/**
    21â†’ * Retry configuration options
    22â†’ */
    23â†’export interface RetryConfig {
    24â†’  /** Maximum number of retry attempts */
    25â†’  maxAttempts: number;
    26â†’  /** Initial delay between retries (ms) */
    27â†’  initialDelayMs: number;
    28â†’  /** Maximum delay between retries (ms) */
    29â†’  maxDelayMs: number;
    30â†’  /** Backoff multiplier (e.g., 2 for exponential) */
    31â†’  backoffMultiplier: number;
    32â†’  /** Add random jitter to delays (prevents thundering herd) */
    33â†’  jitter: boolean;
    34â†’  /** Predicate to determine if an error is retryable */
    35â†’  isRetryable?: (error: unknown) => boolean;
    36â†’  /** Callback invoked before each retry */
    37â†’  onRetry?: (error: unknown, attempt: number, delayMs: number) => void;
    38â†’}
    39â†’
    40â†’/**
    41â†’ * Default retry configuration
    42â†’ * Suitable for most transient failure scenarios
    43â†’ */
    44â†’export const DEFAULT_RETRY_CONFIG: RetryConfig = {
    45â†’  maxAttempts: 3,
    46â†’  initialDelayMs: 1000,
    47â†’  maxDelayMs: 30000,
    48â†’  backoffMultiplier: 2,
    49â†’  jitter: true,
    50â†’  isRetryable: defaultIsRetryable,
    51â†’};
    52â†’
    53â†’/**
    54â†’ * Aggressive retry configuration
    55â†’ * Use for critical operations that must succeed
    56â†’ */
    57â†’export const AGGRESSIVE_RETRY_CONFIG: RetryConfig = {
    58â†’  maxAttempts: 5,
    59â†’  initialDelayMs: 500,
    60â†’  maxDelayMs: 60000,
    61â†’  backoffMultiplier: 2,
    62â†’  jitter: true,
    63â†’  isRetryable: defaultIsRetryable,
    64â†’};
    65â†’
    66â†’/**
    67â†’ * Quick retry configuration
    68â†’ * Use for fast operations where quick recovery is expected
    69â†’ */
    70â†’export const QUICK_RETRY_CONFIG: RetryConfig = {
    71â†’  maxAttempts: 3,
    72â†’  initialDelayMs: 100,
    73â†’  maxDelayMs: 2000,
    74â†’  backoffMultiplier: 2,
    75â†’  jitter: true,
    76â†’  isRetryable: defaultIsRetryable,
    77â†’};
    78â†’
    79â†’/**
    80â†’ * External service retry configuration
    81â†’ * Use for Maximo, OCC, and other external integrations
    82â†’ */
    83â†’export const EXTERNAL_SERVICE_RETRY_CONFIG: RetryConfig = {
    84â†’  maxAttempts: 5,
    85â†’  initialDelayMs: 2000,
    86â†’  maxDelayMs: 60000,
    87â†’  backoffMultiplier: 2,
    88â†’  jitter: true,
    89â†’  isRetryable: (error) => {
    90â†’    // Retry on network errors, timeouts, and 5xx responses
    91â†’    if (error instanceof TimeoutError) return true;
    92â†’    if (error instanceof ExternalServiceError) return true;
    93â†’    if (error instanceof ServiceUnavailableError) return true;
    94â†’
    95â†’    // Check for fetch/network errors
    96â†’    if (error instanceof Error) {
    97â†’      const message = error.message.toLowerCase();
    98â†’      return (
    99â†’        message.includes('network') ||
   100â†’        message.includes('timeout') ||
   101â†’        message.includes('econnrefused') ||
   102â†’        message.includes('econnreset') ||
   103â†’        message.includes('socket hang up')
   104â†’      );
   105â†’    }
   106â†’
   107â†’    return false;
   108â†’  },
   109â†’};
   110â†’
   111â†’/**
   112â†’ * Default function to determine if an error is retryable
   113â†’ */
   114â†’function defaultIsRetryable(error: unknown): boolean {
   115â†’  // Don't retry validation errors or not found errors
   116â†’  if (error instanceof Error) {
   117â†’    const code = (error as Error & { code?: string }).code ?? '';
   118â†’    const statusCode = (error as Error & { statusCode?: number }).statusCode ?? 0;
   119â†’
   120â†’    // Don't retry 4xx client errors (except 408 timeout, 429 rate limit)
   121â†’    if (statusCode >= 400 && statusCode < 500 && statusCode !== 408 && statusCode !== 429) {
   122â†’      return false;
   123â†’    }
   124â†’
   125â†’    // Don't retry certain error codes
   126â†’    if (code.startsWith('BUS_') || code.startsWith('AUTH_')) {
   127â†’      return false;
   128â†’    }
   129â†’  }
   130â†’
   131â†’  return true;
   132â†’}
   133â†’
   134â†’/**
   135â†’ * Calculate delay for a given attempt with optional jitter
   136â†’ */
   137â†’function calculateDelay(attempt: number, config: RetryConfig): number {
   138â†’  const exponentialDelay = config.initialDelayMs * Math.pow(config.backoffMultiplier, attempt - 1);
   139â†’  let delay = Math.min(exponentialDelay, config.maxDelayMs);
   140â†’
   141â†’  if (config.jitter) {
   142â†’    // Add Â±25% jitter
   143â†’    const jitterRange = delay * 0.25;
   144â†’    delay = delay - jitterRange + Math.random() * jitterRange * 2;
   145â†’  }
   146â†’
   147â†’  return Math.round(delay);
   148â†’}
   149â†’
   150â†’/**
   151â†’ * Sleep for a specified duration
   152â†’ */
   153â†’function sleep(ms: number): Promise<void> {
   154â†’  return new Promise((resolve) => setTimeout(resolve, ms));
   155â†’}
   156â†’
   157â†’/**
   158â†’ * Execute a function with retry logic
   159â†’ *
   160â†’ * Uses exponential backoff with optional jitter to handle transient failures.
   161â†’ * Integrates with OpenTelemetry tracing for observability.
   162â†’ *
   163â†’ * @example
   164â†’ * ```typescript
   165â†’ * const result = await withRetry(
   166â†’ *   async () => {
   167â†’ *     return await fetchFromMaximo('/api/workorders');
   168â†’ *   },
   169â†’ *   {
   170â†’ *     maxAttempts: 5,
   171â†’ *     initialDelayMs: 1000,
   172â†’ *     isRetryable: (error) => error instanceof NetworkError
   173â†’ *   },
   174â†’ *   'fetchWorkOrders'
   175â†’ * );
   176â†’ * ```
   177â†’ */
   178â†’export async function withRetry<T>(
   179â†’  fn: () => Promise<T>,
   180â†’  config?: Partial<RetryConfig>,
   181â†’  operationName?: string
   182â†’): Promise<T> {
   183â†’  const opts = { ...DEFAULT_RETRY_CONFIG, ...config };
   184â†’  const name = operationName ?? 'retry';
   185â†’
   186â†’  return withSpan(
   187â†’    `resilience.${name}`,
   188â†’    async (span) => {
   189â†’      span.setAttribute('retry.max_attempts', opts.maxAttempts);
   190â†’      let lastError: unknown;
   191â†’
   192â†’      for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
   193â†’        try {
   194â†’          span.setAttribute('retry.current_attempt', attempt);
   195â†’          addSpanEvent('retry.attempt', { attempt });
   196â†’
   197â†’          const result = await fn();
   198â†’
   199â†’          if (attempt > 1) {
   200â†’            addSpanEvent('retry.success', { attempt, totalAttempts: attempt });
   201â†’          }
   202â†’
   203â†’          return result;
   204â†’        } catch (error) {
   205â†’          lastError = error;
   206â†’
   207â†’          // Check if we should retry
   208â†’          const shouldRetry = attempt < opts.maxAttempts && (opts.isRetryable?.(error) ?? true);
   209â†’
   210â†’          if (!shouldRetry) {
   211â†’            addSpanEvent('retry.exhausted', {
   212â†’              attempt,
   213â†’              error: error instanceof Error ? error.message : String(error),
   214â†’              retryable: opts.isRetryable?.(error) ?? true,
   215â†’            });
   216â†’            throw error;
   217â†’          }
   218â†’
   219â†’          // Calculate delay
   220â†’          const delayMs = calculateDelay(attempt, opts);
   221â†’
   222â†’          addSpanEvent('retry.waiting', {
   223â†’            attempt,
   224â†’            delayMs,
   225â†’            error: error instanceof Error ? error.message : String(error),
   226â†’          });
   227â†’
   228â†’          // Invoke callback if provided
   229â†’          opts.onRetry?.(error, attempt, delayMs);
   230â†’
   231â†’          logger.warn(
   232â†’            {
   233â†’              operation: name,
   234â†’              attempt,
   235â†’              nextAttempt: attempt + 1,
   236â†’              delayMs,
   237â†’              error: error instanceof Error ? error.message : String(error),
   238â†’            },
   239â†’            `Retry attempt ${attempt}/${opts.maxAttempts} failed, waiting ${delayMs}ms`
   240â†’          );
   241â†’
   242â†’          await sleep(delayMs);
   243â†’        }
   244â†’      }
   245â†’
   246â†’      // Should never reach here, but TypeScript needs this
   247â†’      throw lastError;
   248â†’    },
   249â†’    { kind: SpanKind.INTERNAL }
   250â†’  );
   251â†’}
   252â†’
   253â†’// =============================================================================
   254â†’// Circuit Breaker Implementation
   255â†’// =============================================================================
   256â†’
   257â†’/**
   258â†’ * Circuit breaker states
   259â†’ */
   260â†’export type CircuitState = 'CLOSED' | 'OPEN' | 'HALF_OPEN';
   261â†’
   262â†’/**
   263â†’ * Circuit breaker configuration
   264â†’ */
   265â†’export interface CircuitBreakerConfig {
   266â†’  /** Number of failures before opening the circuit */
   267â†’  failureThreshold: number;
   268â†’  /** Number of successes in half-open state to close circuit */
   269â†’  successThreshold: number;
   270â†’  /** Time to wait before transitioning from OPEN to HALF_OPEN (ms) */
   271â†’  resetTimeoutMs: number;
   272â†’  /** Function to determine if an error counts as a failure */
   273â†’  isFailure?: (error: unknown) => boolean;
   274â†’  /** Callback when circuit state changes */
   275â†’  onStateChange?: (from: CircuitState, to: CircuitState) => void;
   276â†’}
   277â†’
   278â†’/**
   279â†’ * Default circuit breaker configuration
   280â†’ */
   281â†’export const DEFAULT_CIRCUIT_BREAKER_CONFIG: CircuitBreakerConfig = {
   282â†’  failureThreshold: 5,
   283â†’  successThreshold: 3,
   284â†’  resetTimeoutMs: 30000,
   285â†’  isFailure: () => true,
   286â†’};
   287â†’
   288â†’/**
   289â†’ * Circuit breaker metrics
   290â†’ */
   291â†’export interface CircuitBreakerMetrics {
   292â†’  state: CircuitState;
   293â†’  failures: number;
   294â†’  successes: number;
   295â†’  lastFailureTime: Date | null;
   296â†’  lastSuccessTime: Date | null;
   297â†’  totalRequests: number;
   298â†’  totalFailures: number;
   299â†’  totalSuccesses: number;
   300â†’}
   301â†’
   302â†’/**
   303â†’ * Circuit Breaker implementation
   304â†’ *
   305â†’ * Prevents cascading failures by stopping requests to a failing service.
   306â†’ * Implements the standard circuit breaker pattern:
   307â†’ * - CLOSED: Normal operation, requests flow through
   308â†’ * - OPEN: Failures exceeded threshold, requests fail fast
   309â†’ * - HALF_OPEN: Testing if service has recovered
   310â†’ *
   311â†’ * @example
   312â†’ * ```typescript
   313â†’ * const maximoBreaker = new CircuitBreaker({
   314â†’ *   failureThreshold: 5,
   315â†’ *   resetTimeoutMs: 30000,
   316â†’ *   onStateChange: (from, to) => {
   317â†’ *     logger.warn({ from, to }, 'Maximo circuit breaker state changed');
   318â†’ *   }
   319â†’ * }, 'maximo');
   320â†’ *
   321â†’ * // In service
   322â†’ * const result = await maximoBreaker.execute(
   323â†’ *   async () => fetchFromMaximo('/api/workorders')
   324â†’ * );
   325â†’ * ```
   326â†’ */
   327â†’export class CircuitBreaker {
   328â†’  private state: CircuitState = 'CLOSED';
   329â†’  private failures = 0;
   330â†’  private successes = 0;
   331â†’  private lastFailureTime: Date | null = null;
   332â†’  private lastSuccessTime: Date | null = null;
   333â†’  private totalRequests = 0;
   334â†’  private totalFailures = 0;
   335â†’  private totalSuccesses = 0;
   336â†’  private readonly config: CircuitBreakerConfig;
   337â†’  private readonly name: string;
   338â†’  private readonly log: typeof logger;
   339â†’
   340â†’  constructor(config: Partial<CircuitBreakerConfig> = {}, name = 'default') {
   341â†’    this.config = { ...DEFAULT_CIRCUIT_BREAKER_CONFIG, ...config };
   342â†’    this.name = name;
   343â†’    this.log = logger.child({ circuitBreaker: name });
   344â†’  }
   345â†’
   346â†’  /**
   347â†’   * Execute a function through the circuit breaker
   348â†’   */
   349â†’  async execute<T>(fn: () => Promise<T>): Promise<T> {
   350â†’    return withSpan(
   351â†’      `circuitBreaker.${this.name}`,
   352â†’      async (span) => {
   353â†’        span.setAttribute('circuit_breaker.name', this.name);
   354â†’        span.setAttribute('circuit_breaker.state', this.state);
   355â†’
   356â†’        this.totalRequests++;
   357â†’
   358â†’        // Check if circuit should transition from OPEN to HALF_OPEN
   359â†’        this.checkResetTimeout();
   360â†’
   361â†’        // If circuit is OPEN, fail fast
   362â†’        if (this.state === 'OPEN') {
   363â†’          addSpanEvent('circuit_breaker.rejected', { state: this.state });
   364â†’          throw new ServiceUnavailableError(
   365â†’            `Circuit breaker ${this.name} is OPEN. Service unavailable.`,
   366â†’            { retryAfter: Math.ceil(this.config.resetTimeoutMs / 1000) }
   367â†’          );
   368â†’        }
   369â†’
   370â†’        try {
   371â†’          const result = await fn();
   372â†’          this.recordSuccess();
   373â†’          addSpanEvent('circuit_breaker.success', { state: this.state });
   374â†’          return result;
   375â†’        } catch (error) {
   376â†’          if (this.config.isFailure?.(error) ?? true) {
   377â†’            this.recordFailure();
   378â†’            addSpanEvent('circuit_breaker.failure', {
   379â†’              state: this.state,
   380â†’              failures: this.failures,
   381â†’            });
   382â†’          }
   383â†’          throw error;
   384â†’        }
   385â†’      },
   386â†’      { kind: SpanKind.INTERNAL }
   387â†’    );
   388â†’  }
   389â†’
   390â†’  /**
   391â†’   * Check if the reset timeout has elapsed and transition to HALF_OPEN
   392â†’   */
   393â†’  private checkResetTimeout(): void {
   394â†’    if (this.state !== 'OPEN' || !this.lastFailureTime) return;
   395â†’
   396â†’    const elapsed = Date.now() - this.lastFailureTime.getTime();
   397â†’    if (elapsed >= this.config.resetTimeoutMs) {
   398â†’      this.transition('HALF_OPEN');
   399â†’    }
   400â†’  }
   401â†’
   402â†’  /**
   403â†’   * Record a successful execution
   404â†’   */
   405â†’  private recordSuccess(): void {
   406â†’    this.successes++;
   407â†’    this.totalSuccesses++;
   408â†’    this.lastSuccessTime = new Date();
   409â†’
   410â†’    if (this.state === 'HALF_OPEN') {
   411â†’      if (this.successes >= this.config.successThreshold) {
   412â†’        this.transition('CLOSED');
   413â†’      }
   414â†’    } else if (this.state === 'CLOSED') {
   415â†’      // Reset failure count on success in CLOSED state
   416â†’      this.failures = 0;
   417â†’    }
   418â†’  }
   419â†’
   420â†’  /**
   421â†’   * Record a failed execution
   422â†’   */
   423â†’  private recordFailure(): void {
   424â†’    this.failures++;
   425â†’    this.totalFailures++;
   426â†’    this.lastFailureTime = new Date();
   427â†’    this.successes = 0; // Reset success count on failure
   428â†’
   429â†’    if (this.state === 'HALF_OPEN') {
   430â†’      // Any failure in HALF_OPEN opens the circuit again
   431â†’      this.transition('OPEN');
   432â†’    } else if (this.state === 'CLOSED') {
   433â†’      if (this.failures >= this.config.failureThreshold) {
   434â†’        this.transition('OPEN');
   435â†’      }
   436â†’    }
   437â†’  }
   438â†’
   439â†’  /**
   440â†’   * Transition to a new state
   441â†’   */
   442â†’  private transition(to: CircuitState): void {
   443â†’    const from = this.state;
   444â†’    if (from === to) return;
   445â†’
   446â†’    this.log.info({ from, to }, `Circuit breaker transitioning: ${from} -> ${to}`);
   447â†’
   448â†’    this.state = to;
   449â†’    this.failures = 0;
   450â†’    this.successes = 0;
   451â†’
   452â†’    this.config.onStateChange?.(from, to);
   453â†’  }
   454â†’
   455â†’  /**
   456â†’   * Get current circuit breaker metrics
   457â†’   */
   458â†’  getMetrics(): CircuitBreakerMetrics {
   459â†’    return {
   460â†’      state: this.state,
   461â†’      failures: this.failures,
   462â†’      successes: this.successes,
   463â†’      lastFailureTime: this.lastFailureTime,
   464â†’      lastSuccessTime: this.lastSuccessTime,
   465â†’      totalRequests: this.totalRequests,
   466â†’      totalFailures: this.totalFailures,
   467â†’      totalSuccesses: this.totalSuccesses,
   468â†’    };
   469â†’  }
   470â†’
   471â†’  /**
   472â†’   * Get current state
   473â†’   */
   474â†’  getState(): CircuitState {
   475â†’    this.checkResetTimeout();
   476â†’    return this.state;
   477â†’  }
   478â†’
   479â†’  /**
   480â†’   * Manually reset the circuit breaker to CLOSED state
   481â†’   * Use with caution - primarily for testing or manual intervention
   482â†’   */
   483â†’  reset(): void {
   484â†’    this.log.warn('Circuit breaker manually reset');
   485â†’    this.state = 'CLOSED';
   486â†’    this.failures = 0;
   487â†’    this.successes = 0;
   488â†’  }
   489â†’
   490â†’  /**
   491â†’   * Manually open the circuit
   492â†’   * Use for graceful degradation scenarios
   493â†’   */
   494â†’  open(): void {
   495â†’    this.log.warn('Circuit breaker manually opened');
   496â†’    this.transition('OPEN');
   497â†’    this.lastFailureTime = new Date();
   498â†’  }
   499â†’}
   500â†’
   501â†’// =============================================================================
   502â†’// Combined Retry + Circuit Breaker
   503â†’// =============================================================================
   504â†’
   505â†’/**
   506â†’ * Execute a function with both retry logic and circuit breaker protection
   507â†’ *
   508â†’ * The circuit breaker wraps the retry logic, so if the circuit is open,
   509â†’ * no retries will be attempted.
   510â†’ *
   511â†’ * @example
   512â†’ * ```typescript
   513â†’ * const result = await withResilience(
   514â†’ *   async () => fetchFromMaximo('/api/workorders'),
   515â†’ *   maximoCircuitBreaker,
   516â†’ *   EXTERNAL_SERVICE_RETRY_CONFIG,
   517â†’ *   'fetchWorkOrders'
   518â†’ * );
   519â†’ * ```
   520â†’ */
   521â†’export async function withResilience<T>(
   522â†’  fn: () => Promise<T>,
   523â†’  circuitBreaker: CircuitBreaker,
   524â†’  retryConfig?: Partial<RetryConfig>,
   525â†’  operationName?: string
   526â†’): Promise<T> {
   527â†’  return circuitBreaker.execute(async () => withRetry(fn, retryConfig, operationName));
   528â†’}
   529â†’
   530â†’// =============================================================================
   531â†’// Timeout Utility
   532â†’// =============================================================================
   533â†’
   534â†’/**
   535â†’ * Execute a function with a timeout
   536â†’ *
   537â†’ * @example
   538â†’ * ```typescript
   539â†’ * const result = await withTimeout(
   540â†’ *   async () => slowOperation(),
   541â†’ *   5000,
   542â†’ *   'slowOperation'
   543â†’ * );
   544â†’ * ```
   545â†’ */
   546â†’export async function withTimeout<T>(
   547â†’  fn: () => Promise<T>,
   548â†’  timeoutMs: number,
   549â†’  operationName?: string
   550â†’): Promise<T> {
   551â†’  const name = operationName ?? 'operation';
   552â†’
   553â†’  return new Promise((resolve, reject) => {
   554â†’    const timer = setTimeout(() => {
   555â†’      reject(
   556â†’        new TimeoutError(`Operation ${name} timed out after ${timeoutMs}ms`, {
   557â†’          operation: name,
   558â†’          timeoutMs,
   559â†’        })
   560â†’      );
   561â†’    }, timeoutMs);
   562â†’
   563â†’    fn()
   564â†’      .then((result) => {
   565â†’        clearTimeout(timer);
   566â†’        resolve(result);
   567â†’      })
   568â†’      .catch((error) => {
   569â†’        clearTimeout(timer);
   570â†’        reject(error);
   571â†’      });
   572â†’  });
   573â†’}
   574â†’

